@* Vertical sidebar navigation for settings sections *@

<nav class="settings-sidebar">
    <h5 class="sidebar-title">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link @(section == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section)">
                    <span class="section-icon">@GetIcon(section)</span>
                    @section
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

@using sv_35d7aa86f1ff4a16a8358098ff0d1f96.Services

<div class="settings-section">
    <h3>Profile</h3>
    <p class="text-muted">Manage your personal information</p>
    <hr />

    @if (_profile is not null)
    {
        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label class="form-label fw-semibold">Display Name</label>
                    <input type="text" class="form-control" @bind="_displayName" />
                </div>
                <div class="mb-3">
                    <label class="form-label fw-semibold">Email</label>
                    <input type="email" class="form-control" @bind="_email" />
                </div>
                <div class="mb-3">
                    <label class="form-label fw-semibold">Bio</label>
                    <textarea class="form-control" rows="4" @bind="_bio"></textarea>
                </div>
            </div>
            <div class="col-md-4">
                <div class="avatar-preview text-center">
                    <label class="form-label fw-semibold d-block">Avatar Preview</label>
                    <img src="@_profile.AvatarUrl" alt="Avatar" class="rounded-circle mb-2" width="120" height="120" />
                    <div class="text-muted small text-break">@_profile.AvatarUrl</div>
                </div>
            </div>
        </div>

        <div class="d-flex gap-2 mt-3">
            <button class="btn btn-primary" @onclick="SaveAsync">Save Changes</button>
            <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
        </div>

        @if (_showSuccess)
        {
            <div class="alert alert-success mt-3 d-flex align-items-center" role="alert">
                <span class="me-2">✅</span> Profile saved successfully!
            </div>
        }
    }
    else
    {
        <div class="text-center py-4">
            <div class="spinner-border text-primary" role="status"></div>
            <p class="mt-2 text-muted">Loading profile...</p>
        </div>
    }
</div>

@code {
    [Parameter] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private UserProfile? _profile;
    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private bool _showSuccess;

    protected override void OnParametersSet()
    {
        if (Profile is not null && _profile is null)
        {
            SetFromProfile(Profile);
        }
    }

    private void SetFromProfile(UserProfile p)
    {
        _profile = p;
        _displayName = p.DisplayName;
        _email = p.Email;
        _bio = p.Bio;
    }

    private async Task SaveAsync()
    {
        if (_profile is null) return;
        var updated = _profile with { DisplayName = _displayName, Email = _email, Bio = _bio };
        await OnSave.InvokeAsync(updated);
        _profile = updated;
        _showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }

    private void Discard()
    {
        if (_profile is not null)
        {
            _displayName = _profile.DisplayName;
            _email = _profile.Email;
            _bio = _profile.Bio;
        }
        _showSuccess = false;
    }
}

@using sv_35d7aa86f1ff4a16a8358098ff0d1f96.Services

<div class="settings-section">
    <h3>Notifications</h3>
    <p class="text-muted">Control how you receive notifications</p>
    <hr />

    @if (_prefs is not null)
    {
        <div class="mb-4">
            <h5>Notification Channels</h5>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
                <label class="form-check-label" for="emailNotif">
                    <strong>Email Notifications</strong>
                    <div class="text-muted small">Receive notifications via email</div>
                </label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
                <label class="form-check-label" for="pushNotif">
                    <strong>Push Notifications</strong>
                    <div class="text-muted small">Receive push notifications in your browser</div>
                </label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">
                    <strong>Weekly Digest</strong>
                    <div class="text-muted small">Receive a weekly summary email</div>
                </label>
            </div>
        </div>

        <div class="mb-4">
            <h5>Muted Channels</h5>
            <p class="text-muted small">Uncheck to unmute a channel</p>

            @foreach (var channel in _mutedChannels)
            {
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                           checked="@_channelMuteStates[channel]"
                           @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                    <label class="form-check-label text-capitalize" for="@($"ch-{channel}")">
                        @channel
                    </label>
                </div>
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync">Save Preferences</button>

        @if (_showSuccess)
        {
            <div class="alert alert-success mt-3">
                <span class="me-2">✅</span> Notification preferences saved!
            </div>
        }
    }
    else
    {
        <div class="text-center py-4">
            <div class="spinner-border text-primary" role="status"></div>
            <p class="mt-2 text-muted">Loading preferences...</p>
        </div>
    }
</div>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private NotificationPrefs? _prefs;
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<string> _mutedChannels = [];
    private Dictionary<string, bool> _channelMuteStates = new();
    private bool _showSuccess;

    protected override void OnParametersSet()
    {
        if (Prefs is not null && _prefs is null)
        {
            _prefs = Prefs;
            _emailNotifications = Prefs.EmailNotifications;
            _pushNotifications = Prefs.PushNotifications;
            _weeklyDigest = Prefs.WeeklyDigest;
            _mutedChannels = [.. Prefs.MutedChannels];
            _channelMuteStates = _mutedChannels.ToDictionary(c => c, _ => true);
        }
    }

    private void ToggleChannel(string channel, bool muted)
    {
        _channelMuteStates[channel] = muted;
    }

    private async Task SaveAsync()
    {
        var stillMuted = _channelMuteStates
            .Where(kv => kv.Value)
            .Select(kv => kv.Key)
            .ToList();

        var updated = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, stillMuted);
        await OnSave.InvokeAsync(updated);
        _prefs = updated;
        _showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

@if (Visible)
{
    <div class="modal-backdrop show" @onclick="Cancel"></div>
    <div class="modal d-block" tabindex="-1">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session on <strong>@DeviceName</strong>?</p>
                    <p class="text-muted small">This will sign out the device immediately.</p>
                </div>
                <div class="modal-footer">
                    <button type="button" class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button type="button" class="btn btn-danger" @onclick="Confirm">Revoke Session</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public bool Visible { get; set; }
    [Parameter] public string DeviceName { get; set; } = "";
    [Parameter] public EventCallback OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private async Task Confirm() => await OnConfirm.InvokeAsync();
    private async Task Cancel() => await OnCancel.InvokeAsync();
}

