{"file_text": "@using sv_35d7aa86f1ff4a16a8358098ff0d1f96.Services

<div class="settings-section">
    <h3>Appearance</h3>
    <p class="text-muted">Customize the look and feel</p>
    <hr />

    @if (_settings is not null)
    {
        <div class="row">
            <div class="col-md-7">
                <div class="mb-4">
                    <h5>Theme</h5>
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme" id="@($"theme-{theme}")"
                                   value="@theme" checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h5>Font Size</h5>
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check form-check-inline">
                            <input class="form-check-input" type="radio" name="fontSize" id="@($"fs-{size}")"
                                   value="@size" checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h5>Language</h5>
                    <select class="form-select" style="max-width: 250px;" @bind="_language">
                        @foreach (var lang in Languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>

                <div class="mb-4">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                        <label class="form-check-label" for="compactMode">
                            <strong>Compact Mode</strong>
                            <div class="text-muted small">Reduce spacing and padding throughout the UI</div>
                        </label>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="SaveAsync">Save</button>

                @if (_showSuccess)
                {
                    <div class="alert alert-success mt-3 py-2">
                        <span class="me-2">✅</span> Appearance settings saved!
                    </div>
                }
            </div>

            <div class="col-md-5">
                <h5>Live Preview</h5>
                <div class="preview-area @GetPreviewClasses()" style="@GetPreviewStyles()">
                    <div class="preview-header">
                        <strong>Preview Panel</strong>
                    </div>
                    <div class="preview-body">
                        <p>This is how your content will look with the selected settings.</p>
                        <button class="btn btn-sm @(_theme == "Dark" ? "btn-light" : "btn-primary")">
                            Sample Button
                        </button>
                        <div class="mt-2">
                            <span class="badge @(_theme == "Dark" ? "bg-light text-dark" : "bg-secondary")">Tag</span>
                            <span class="badge @(_theme == "Dark" ? "bg-light text-dark" : "bg-info")">Label</span>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    }
    else
    {
        <div class="text-center py-4">
            <div class="spinner-border text-primary" role="status"></div>
            <p class="mt-2 text-muted">Loading appearance settings...</p>
        </div>
    }
</div>

@code {
    [Parameter] public AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private AppearanceSettings? _settings;
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _showSuccess;

    private static readonly string[] Languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese", "Korean"];

    protected override void OnParametersSet()
    {
        if (Settings is not null && _settings is null)
        {
            _settings = Settings;
            _theme = Settings.Theme;
            _fontSize = Settings.FontSize;
            _language = Settings.Language;
            _compactMode = Settings.CompactMode;
        }
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string> { "border", "rounded" };
        if (_compactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private string GetPreviewStyles()
    {
        var bg = _theme switch { "Dark" => "#1e1e1e", "System" => "#f0f0f0", _ => "#ffffff" };
        var fg = _theme == "Dark" ? "#e0e0e0" : "#212529";
        var fs = _fontSize switch { "Small" => "0.85rem", "Large" => "1.15rem", _ => "1rem" };
        var padding = _compactMode ? "0.5rem" : "1rem";
        return $"background-color:{bg}; color:{fg}; font-size:{fs}; padding:{padding}; min-height:200px;";
    }

    private async Task SaveAsync()
    {
        var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await OnSave.InvokeAsync(updated);
        _settings = updated;
        _showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}
