@using sv_35d7aa86f1ff4a16a8358098ff0d1f96.Services

<div class="settings-section">
    <h3>Security</h3>
    <p class="text-muted">Manage your account security</p>
    <hr />

    @if (_settings is not null)
    {
        <ChangePasswordPanel OnChangePassword="HandleChangePassword" />

        <div class="card mb-3">
            <div class="card-body d-flex justify-content-between align-items-center">
                <div>
                    <strong>Two-Factor Authentication</strong>
                    <div class="text-muted small">Add an extra layer of security to your account</div>
                </div>
                <div class="d-flex align-items-center gap-2">
                    <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                    <div class="form-check form-switch mb-0">
                        <input class="form-check-input" type="checkbox" @bind="_twoFactorEnabled" />
                    </div>
                </div>
            </div>
        </div>

        @if (_settings.LastPasswordChange.HasValue)
        {
            <p class="text-muted small">
                Last password change: @_settings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
            </p>
        }

        <h5 class="mt-4">Active Sessions</h5>
        <div class="table-responsive">
            <table class="table table-hover">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in _settings.Sessions)
                    {
                        var isCurrent = session == _settings.Sessions.First();
                        <tr>
                            <td>
                                @session.Device
                                @if (isCurrent)
                                {
                                    <span class="badge bg-primary ms-1">Current</span>
                                }
                            </td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (!isCurrent)
                                {
                                    <button class="btn btn-outline-danger btn-sm"
                                            @onclick="() => PromptRevoke(session)">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>

        <RevokeSessionDialog Visible="_showRevokeDialog"
                             DeviceName="@(_sessionToRevoke?.Device ?? "")"
                             OnConfirm="ConfirmRevoke"
                             OnCancel="CancelRevoke" />
    }
    else
    {
        <div class="text-center py-4">
            <div class="spinner-border text-primary" role="status"></div>
            <p class="mt-2 text-muted">Loading security settings...</p>
        </div>
    }
</div>

@code {
    [Parameter] public SecuritySettings? Settings { get; set; }
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private SecuritySettings? _settings;
    private bool _twoFactorEnabled;
    private bool _showRevokeDialog;
    private ActiveSession? _sessionToRevoke;

    protected override void OnParametersSet()
    {
        if (Settings is not null)
        {
            _settings = Settings;
            _twoFactorEnabled = Settings.TwoFactorEnabled;
        }
    }

    private async Task HandleChangePassword((string Current, string New) args)
    {
        await OnChangePassword.InvokeAsync(args);
    }

    private void PromptRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is not null)
        {
            await OnRevokeSession.InvokeAsync(_sessionToRevoke.Id);
        }
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }

    private void CancelRevoke()
    {
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours} hours ago";
        return $"{(int)diff.TotalDays} days ago";
    }
}

