toolArgs.file_text:
.settings-dashboard {
    display: flex;
    gap: 2rem;
    min-height: 600px;
}

/* Sidebar */
::deep .settings-sidebar {
    min-width: 220px;
    max-width: 220px;
    background: #f8f9fa;
    border-radius: 0.5rem;
    padding: 1rem 0;
    height: fit-content;
    border: 1px solid #e9ecef;
}

::deep .sidebar-title {
    padding: 0 1rem 0.75rem;
    margin: 0;
    color: #6c757d;
    font-size: 0.75rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

::deep .settings-sidebar .nav-link {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.6rem 1rem;
    color: #495057;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    font-size: 0.95rem;
    border-left: 3px solid transparent;
    transition: all 0.15s ease;
    cursor: pointer;
}

::deep .settings-sidebar .nav-link:hover {
    background: #e9ecef;
    color: #212529;
}

::deep .settings-sidebar .nav-link.active {
    background: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
    font-weight: 600;
}

::deep .section-icon {
    font-size: 1.1rem;
}

/* Content area */
.settings-content {
    flex: 1;
    min-width: 0;
}

::deep .settings-section {
    background: #fff;
    border: 1px solid #e9ecef;
    border-radius: 0.5rem;
    padding: 1.5rem;
}

/* Avatar */
::deep .avatar-preview {
    padding: 1rem;
    background: #f8f9fa;
    border-radius: 0.5rem;
    border: 1px solid #e9ecef;
}

/* Preview area */
::deep .preview-area {
    transition: all 0.2s ease;
}

::deep .preview-header {
    border-bottom: 1px solid rgba(128, 128, 128, 0.3);
    padding-bottom: 0.5rem;
    margin-bottom: 0.75rem;
}

::deep .preview-compact .preview-body {
    line-height: 1.3;
}

/* Modal backdrop fix */
::deep .modal-backdrop {
    position: fixed;
    inset: 0;
    z-index: 1040;
    background: rgba(0, 0, 0, 0.5);
}

::deep .modal.d-block {
    position: fixed;
    inset: 0;
    z-index: 1050;
}

